PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE servers (id INTEGER PRIMARY KEY AUTOINCREMENT, url TEXT UNIQUE NOT NULL, name TEXT, description TEXT, category TEXT DEFAULT 'uncategorized', first_seen TEXT DEFAULT (datetime('now')), last_checked TEXT, total_calls INTEGER DEFAULT 0, successful_calls INTEGER DEFAULT 0, failed_calls INTEGER DEFAULT 0, avg_latency_ms REAL DEFAULT 0, p95_latency_ms REAL DEFAULT 0, uptime_30d REAL DEFAULT 0, trust_score REAL DEFAULT 50.0, static_score REAL DEFAULT 50.0, runtime_score REAL DEFAULT 50.0, github_url TEXT, github_stars INTEGER DEFAULT 0, has_auth INTEGER DEFAULT 0, last_error TEXT, last_error_time TEXT);
CREATE TABLE interactions (id INTEGER PRIMARY KEY AUTOINCREMENT, server_id INTEGER NOT NULL, timestamp TEXT DEFAULT (datetime('now')), agent_id TEXT, tool_name TEXT, success INTEGER NOT NULL, latency_ms REAL, error_type TEXT, error_message TEXT, http_status INTEGER, FOREIGN KEY (server_id) REFERENCES servers(id));
CREATE TABLE baselines (id INTEGER PRIMARY KEY AUTOINCREMENT, category TEXT NOT NULL, metric TEXT NOT NULL, avg_value REAL, p50_value REAL, p95_value REAL, min_value REAL, max_value REAL, sample_count INTEGER DEFAULT 0, last_updated TEXT DEFAULT (datetime('now')), UNIQUE(category, metric));
CREATE TABLE daily_snapshots (id INTEGER PRIMARY KEY AUTOINCREMENT, server_id INTEGER NOT NULL, date TEXT NOT NULL, total_calls INTEGER DEFAULT 0, successful_calls INTEGER DEFAULT 0, avg_latency_ms REAL, p95_latency_ms REAL, trust_score REAL, UNIQUE(server_id, date), FOREIGN KEY (server_id) REFERENCES servers(id));
CREATE TABLE reports (id INTEGER PRIMARY KEY AUTOINCREMENT, report_date TEXT UNIQUE NOT NULL, week_start TEXT NOT NULL, week_end TEXT NOT NULL, total_interactions INTEGER DEFAULT 0, external_interactions INTEGER DEFAULT 0, probe_interactions INTEGER DEFAULT 0, keeper_interactions INTEGER DEFAULT 0, new_servers_added INTEGER DEFAULT 0, categories_with_baselines INTEGER DEFAULT 0, top_reliable_servers TEXT, drift_incidents TEXT, category_updates TEXT, created_at TEXT DEFAULT (datetime('now')));
DELETE FROM sqlite_sequence;
CREATE INDEX idx_interactions_server ON interactions(server_id);
CREATE INDEX idx_interactions_timestamp ON interactions(timestamp);
CREATE INDEX idx_servers_category ON servers(category);
CREATE INDEX idx_servers_trust ON servers(trust_score DESC);
CREATE INDEX idx_daily_server_date ON daily_snapshots(server_id, date);
CREATE INDEX idx_reports_date ON reports(report_date DESC);
